	private static Object invokeConfig(LmdbStoreConfig config, String methodName, Class<?> parameterType, Object value)
			throws Exception {
		Method method = LmdbStoreConfig.class.getMethod(methodName, parameterType);
		return assertDoesNotThrow(() -> method.invoke(config, value));
	}

	private static Object objectField(Object target, String name) throws Exception {
		Field field = target.getClass().getDeclaredField(name);
		field.setAccessible(true);
		return field.get(target);
	}

	private static void assertNoDeclaredField(Object target, String name) {
		assertThrows(NoSuchFieldException.class, () -> target.getClass().getDeclaredField(name),
				"LMDB sinks should not retain estimator-owned state in field " + name);
	}

	private static void setObjectField(Object target, String name, Object value) throws Exception {
		Field field = target.getClass().getDeclaredField(name);
		field.setAccessible(true);
		field.set(target, value);
	}

	private static int pendingIncrementalStatementQueueSize(SketchBasedJoinEstimator estimator) throws Exception {
		Object[] queues = (Object[]) objectField(estimator, "incrementalStatementQueues");
		int pending = 0;
		for (Object queue : queues) {
			pending += ((Number) objectField(queue, "updateCount")).intValue();
		}
		return pending;
	}

	private static int pendingLmdbEstimatorAddCount(SailSink sink) throws Exception {
		List<?> pending = (List<?>) objectField(sink, "pendingEstimatorAdds");
		return pending == null ? 0 : pending.size();
	}

	private static void flushPendingIncremental(SketchBasedJoinEstimator estimator) throws Exception {
		Method method = SketchBasedJoinEstimator.class.getDeclaredMethod("debugFlushPendingIncremental");
		method.setAccessible(true);
		assertDoesNotThrow(() -> method.invoke(estimator));
	}

	private static Object component(Object stateComponents, String component) throws Exception {
		Field field = stateComponents.getClass().getDeclaredField(component);
		field.setAccessible(true);
		return field.get(stateComponents);
	}

	private static int componentArrayLength(Object stateComponents, String component) throws Exception {
		return ((AtomicReferenceArray<?>) component(stateComponents, component)).length();
	}

	private static int configuredBucketCount(String propertyName, int configValue) {
		String value = System.getProperty(ESTIMATOR_PROPERTY_PREFIX + propertyName);
		return value == null ? configValue : Integer.parseInt(value);
	}

	private static void withEstimatorProperty(String name, String value, ThrowingRunnable runnable) throws Exception {
		String key = ESTIMATOR_PROPERTY_PREFIX + name;
		String previous = System.getProperty(key);
		System.setProperty(key, value);
		try {
			runnable.run();
		} finally {
			if (previous == null) {
				System.clearProperty(key);
			} else {
				System.setProperty(key, previous);
			}
		}
	}

	private static File estimatorStore(File dataDir) {
		return new File(dataDir, SNAPSHOT_FILE);
	}

	private static File estimatorMetadata(File dataDir) {
		return new File(estimatorStore(dataDir), SNAPSHOT_METADATA_FILE);
	}

